en.ConversionModal = "<h2 class='modal-header black'>Warning!</h2><p><b>Deposits opening in foreign currency is made with the card in local currency.</b></p><p>Purchase of foreign currency made at the rate of the Bank on the day of the operation.</p>", locale.ua.ConversionModal = "<h2 class='modal-header black'>Увага!</h2><p><b>Оформлення депозиту в іноземній валюті проводиться з картки в гривні.</b></p><p>Купівля іноземної валюти здійснюється за курсом Банку на день проведення операції.</p>", locale.ru.ConversionModal = "<h2 class='modal-header black'>Внимание!</h2><p><b>Оформление депозита в иностранной валюте проводится c карты в гривне.</b></p><p>Покупка иностранной валюты проводится по курсу Банка на день проведения операции.</p>", locale.en.NoTaxDepModal = '<p style=\'text-align:left;\'>К сожалению, у Вас нет Карты для выплат, к которой можно подключить "Стандарт безналоговый".</p><p style=\'text-align:left;\'>Если Вы получаете в ПриватБанке зарплату, пенсию, стипендию или социальную помощь и желаете оформить услугу"Стандарт безналоговый", обратитесь, пожалуйста, в любое отделение, чтобы перевыпустить Вашу карту. Выпуск Карты для выплат (без фотографии) проводится бесплатно. После получения новой карты Вы сможете оформить "Стандарт безналоговый".', locale.ua.NoTaxDepModal = "<p style='text-align:left;'>На жаль, у Вас немає Картки для виплат, до якої можна підключити «Стандарт безподатковий».</p><p style='text-align:left;'>Якщо Ви отримуєте в ПриватБанку зарплату, пенсію, стипендію або соціальну допомогу та бажаєте оформити послугу «Стандарт безподатковий», зверніться, будь ласка, у будь-яке відділення, щоб перевипустити Вашу картку. Випуск Картки для виплат (без фотографії) проводиться безкоштовно. Після отримання нової картки Ви зможете оформити «Стандарт безподатковий».", locale.ru.NoTaxDepModal = '<p style=\'text-align:left;\'>К сожалению, у Вас нет Карты для выплат, к которой можно подключить "Стандарт безналоговый".</p><p style=\'text-align:left;\'>Если Вы получаете в ПриватБанке зарплату, пенсию, стипендию или социальную помощь и желаете оформить услугу"Стандарт безналоговый", обратитесь, пожалуйста, в любое отделение, чтобы перевыпустить Вашу карту. Выпуск Карты для выплат (без фотографии) проводится бесплатно. После получения новой карты Вы сможете оформить "Стандарт безналоговый".', locale.en.NoTaxDepModal_AB = '<p style=\'text-align:left;\'>К сожалению, у Вас нет Карты для выплат, к которой можно подключить "Стандарт безналоговый".</p><p style=\'text-align:left;\'>Если Вы получаете в А-Банке зарплату, пенсию, степендию или социальную помошь и желаете оформить улсугу"Стандарт безналоговый", обратитесь, пожалуйста, в любое отделение, чтобы перевыпустить Вашу карту. Выпуск Карты для выплат (без фотографии) проводится бесплатно. После получения новой карты Вы сможете оформить "Стандарт безналоговый".', locale.ua.NoTaxDepModal_AB = "<p style='text-align:left;'>На жаль, у Вас немає Картки для виплат, до якої можна підключити «Стандарт безподатковий».</p><p style='text-align:left;'>Якщо Ви отримуєте в А-Банку зарплату, пенсію, стипендію або соціальну допомогу та бажаєте оформити послугу «Стандарт безподатковий», зверніться, будь ласка, у будь-яке відділення, щоб перевипустити Вашу картку. Випуск Картки для виплат (без фотографії) проводиться безкоштовно. Після отримання нової картки Ви зможете оформити «Стандарт безподатковий».", locale.ru.NoTaxDepModal_AB = '<p style=\'text-align:left;\'>К сожалению, у Вас нет Карты для выплат, к которой можно подключить "Стандарт безналоговый".</p><p style=\'text-align:left;\'>Если Вы получаете в А-Банке зарплату, пенсию, степендию или социальную помошь и желаете оформить улсугу "Стандарт безналоговый", обратитесь, пожалуйста, в любое отделение, чтобы перевыпустить Вашу карту. Выпуск Карты для выплат (без фотографии) проводится бесплатно. После получения новой карты Вы сможете оформить "Стандарт безналоговый".', locale.ru.AtoModal = '<div><div>У вас есть счета, открытые на отделениях в зоне ATO.</div><br></div><div><div>Согласно Указа Президента Украины №875/2014 от 04.11.2014 г. <b>приостанавливается обслуживание счетов, открытых на территориях в районе проведения АТО.</b></div></div><div><div><b>Возобновление обслуживания</b> возможно после подписания Вами "Заявления о проживании вне зоны АТО" с указанием нового адреса проживания.</div></div><br><div><div>Для подписания Заявления обратитесь пожалуйста в любое отделение ' + ("AB" == bank ? "А-Банка" : "ПриватБанка") + ".</div></div>", locale.ua.AtoModal = "<div><div>У Вас є рахунки, відкриті на відділеннях в зоні АТО.</div><br></div><div><div>Згідно Указу Президента України №875/2014 від 04.11.2014 р. <b> призупиняється обслуговування рахунків, відкритих на територіях в районі проведення АТО.</b></div></div><div><div><b>Відновлення обслуговування</b> можливе після підписання Вами заяви про проживання поза зоною АТО із зазначенням нової адреси проживання.</div></div><br><div><div>Для підписання Заяви зверніться будь ласка в будь-яке відділення " + ("AB" == bank ? "А-Банку" : "ПриватБанку") + ".</div></div>", locale.en.AtoModal = '<div><div>У вас есть счета, открытые на отделениях в зоне ATO.</div><br></div><div><div>Согласно Указа Президента Украины №875/2014 от 04.11.2014 г. <b>приостанавливается обслуживание счетов, открытых на территориях в районе проведения АТО.</b></div></div><div><div><b>Возобновление обслуживания</b> возможно после подписания Вами "Заявления о проживании вне зоны АТО" с указанием нового адреса проживания.</div></div><br><div><div>Для подписания Заявления обратитесь пожалуйста в любое отделение ' + ("AB" == bank ? "А-Банка" : "ПриватБанка") + ".</div></div>", locale.en.ConversionWarning = "Card currency is different from deposit currency, the conversion will be made at the rate of card and deposit ", locale.ua.ConversionWarning = "Валюта картки відрізняється від валюти депозиту, конвертація буде здійснена за курсом для вкладів ", locale.ru.ConversionWarning = "Валюта карты отличается от валюты депозита, конвертация будет произведена по курсу для вкладов ", locale.en.ConversionWarningP2Open = "<br><span style='color:#333'>Увага! Згідно з постановою НБУ № XXX. Ви можете сьогодні оформити депозит з картки в гривні на суму не більше XXX XXX (екв. XXX грн).</span>", locale.ua.ConversionWarningP2Open = "<br><span style='color:#333'>Увага! Згідно з постановою НБУ № XXX. Ви можете сьогодні оформити депозит з картки в гривні на суму не більше XXX XXX (екв. XXX грн).</span>", locale.ru.ConversionWarningP2Open = "<br><span style='color:#333'>Внимание! Согласно постановлению НБУ № XXX Вы можете сегодня оформить депозит с карты в гривне на сумму не более XXX XXX (экв. XXX грн).</span>", locale.en.ConversionWarningP2Charge = "<span style='color:#333'>Увага! Згідно з постановою НБУ № XXX. Ви можете сьогодні поповнити депозит з картки в гривні на суму не більше XXX XXX (екв. XXX грн).</span>", locale.ua.ConversionWarningP2Charge = "<span style='color:#333'>Увага! Згідно з постановою НБУ № XXX. Ви можете сьогодні поповнити депозит з картки в гривні на суму не більше XXX XXX (екв. XXX грн).</span>", locale.ru.ConversionWarningP2Charge = "<span style='color:#333'>Внимание! Согласно постановлению НБУ № XXX Вы можете сегодня пополнить депозит с карты в гривне на сумму не более XXX XXX (экв. XXX грн).</span>", locale.en.InetWarning = "Получение наличных с интернет карты невозможно. Если Вы планируете снимать наличные без комиссий, рекомендуем выбрать Карту для выплат.", locale.ua.InetWarning = "Отримання готiвки з iнтернет карти неможливе. Якщо Ви плануєте знiмати готiвку без комiсiй, рекомендуємо обрати Картку для виплат.", locale.ru.InetWarning = "Получение наличных с интернет карты невозможно. Если Вы планируете снимать наличные без комиссий, рекомендуем выбрать Карту для выплат.", locale.en.financeUAH = "Hrivna", locale.ua.financeUAH = "Гривень", locale.ru.financeUAH = "Гривен", locale.en.financeUSD = "US Dollars", locale.ua.financeUSD = "Доларів США", locale.ru.financeUSD = "Долларов США", locale.en.financeEUR = "Euro", locale.ua.financeEUR = "Євро", locale.ru.financeEUR = "Евро", locale.en.chartFinTitle_uah = "The structure of your savings in hryvnia equivalent", locale.ua.chartFinTitle_uah = "Структура Ваших заощаджень в гривневому еквіваленті", locale.ru.chartFinTitle_uah = "Структура Ваших сбережений в гривневом эквиваленте", locale.en.chartFinTitle_usd = "The structure of your savings in dollar  equivalent", locale.ua.chartFinTitle_usd = "Структура Ваших заощаджень у доларовому еквіваленті", locale.ru.chartFinTitle_usd = "Структура Ваших сбережений в долларовом эквиваленте", locale.en.chartFinTitle_eur = "The structure of your savings in the euro equivalent", locale.ua.chartFinTitle_eur = "Структура Ваших заощаджень в євровому еквіваленті", locale.ru.chartFinTitle_eur = "Структура Ваших сбережений в евровом эквиваленте", locale.en.currentEqvSum = "Поточна сума Ваших заощаджень в гривневому<br>еквіваленті ", locale.ua.currentEqvSum = "Поточна сума Ваших заощаджень в гривневому<br>еквіваленті ", locale.ru.currentEqvSum = "Текущая сумма Ваших сбережений в гривневом<br>эквиваленте ", locale.en.forecast_forToday = "на сегодня", locale.ua.forecast_forToday = "на сьогодні", locale.ru.forecast_forToday = "на сегодня", locale.en.forecast_capital = "Капитал", locale.ua.forecast_capital = "Капітал", locale.ru.forecast_capital = "Капитал", locale.en.forecast_eqvMonth = "Доход, грн.экв.<br>(ежемесячный)", locale.ua.forecast_eqvMonth = "Доход, грн.екв.<br>(щомісячно)", locale.ru.forecast_eqvMonth = "Доход, грн.экв.<br>(ежемесячный)", locale.en.forecast_eqvAcc = "Доход, грн.экв.<br>(накопительный) *", locale.ua.forecast_eqvAcc = "Доход, грн.екв.<br>(накопичувальний) *", locale.ru.forecast_eqvAcc = "Доход, грн.экв.<br>(накопительный) *", locale.en.forecast_uahMonth = "Доход, грн.<br>(ежемесячный)", locale.ua.forecast_uahMonth = "Доход, грн.<br>(щомісячно)", locale.ru.forecast_uahMonth = "Доход, грн.<br>(ежемесячный)", l